import{_ as e,o as b,c as t,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"肘术师","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/肘术师.md","filePath":"4.资源分区/6.技艺及称号/杂项/肘术师.md"}'),s={name:"4.资源分区/6.技艺及称号/杂项/肘术师.md"};function o(d,a,l,i,_,c){return b(),t("div",null,[...a[0]||(a[0]=[r("h1",{id:"肘术师",tabindex:"-1"},[n("肘术师 "),r("a",{class:"header-anchor",href:"#肘术师","aria-label":'Permalink to "肘术师"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),p('<h1 id="肘术师-1" tabindex="-1">肘术师 <a class="header-anchor" href="#肘术师-1" aria-label="Permalink to &quot;肘术师&quot;">​</a></h1><p>肘术师<br> 介绍：man！ what can I say~ Manba out！</p><p>肘与小腹的互相吸引<br> 价格：C+1000<br> 动作：标准动作<br> 目标：单一目标<br> 距离：触及距离<br> 描述：<br> 被绊摔倒地的敌人空门大开，就像小狗一样露出腹部等着你来抚摸。肘术师，你感受到了吗，手肘不自主的震动，是的，它已经迫不及待去爱抚了，遵从肘之意志的召唤，跃起然后，下肘吧！<br> 效果:<br> 选择[倒地]状态的敌人为目标，进行一次普通近战肉搏攻击，本次攻击具有【余波】特性，获得2DP的技艺加值且附带伤害出目一半的剧痛点数，正常豁免。</p><p>像风暴一样，肘击吧！<br> 价格：C+1000<br> 动作：整轮动作<br> 目标：单一目标<br> 距离：触及距离<br> 描述：速度*质量=伤害。跑起来，肘术师，跑起来。压低重心调整角度，如同即将到来的风暴一样，让那些看轻肘术师的人，高高的飞起来！<br> 效果：<br> 你进行一次冲锋攻击，本次冲锋攻击可以进行曲线冲锋，同时攻击冲锋触及范围内的所有敌人，同时可以选择将攻击转化为C级的【击飞】效果</p><p>为对手献上敬意，黑肘！！<br> 价格：B+2500<br> 动作：标准动作<br> 目标：单一目标<br> 距离：触及距离<br> 描述：<br> 肘力在打击产生后0.000001秒内击中目标的瞬间，空间将会扭曲，攻击将会散发黑色的光芒，这就是，黑肘！<br> 效果：<br> 基因锁开启的状况下才能使用，进行一次普通肉搏攻击，本次攻击附带【能量武器】特性，攻击检定成功数增加一半（每轮仅生效一次），且附带等同于伤害出目的眩晕点数，正常豁免。</p><p>连接起牵绊吧，肘术师<br> 价格：B+2000<br> 射程：30+传奇操纵*10米<br> 动作：移动动作<br> 持续：一场景<br> 描述：是了，肘术师有时会单打独斗，但那并非长久之技。旅途之中与同伴的互相扶持，所经历的悲欢喜乐，那一点一滴凝聚而成的情谊与牵绊，才是肘术师不断战胜他人，延续至今的奥义<br> 效果：<br> 当一名角色与你相处的经历至少超过一影片，或者在影片内相处超过至少1周时。于战斗外，在对方同意的情况下，你可以令他成为[复肘者]，持续一影片，你最多可以令4名角色成为[复肘者]，这是一个B级信息来源的模因效果。</p><p>在战斗中，你可以消耗移动动作令你与范围内的所有[复肘者]，于本次场景内获得：每轮一次，攻击相关检定可以重掷一次，取其中较高的一次进行结算。</p><p>复肘者，集结！<br> 前提：连接起牵绊吧，肘术师<br> 价格：A+4000<br> 动作：标准动作<br> 距离：特殊<br> 描述：<br> 正如我们之前所说，肘术师的奥义其实是，一路连接起的牵绊，当你身处绝地时，它将化作纽带连接你们彼此，所以，大声呼喊吧！<br> 效果：<br> 当你孤身一人并面对高一级的敌人或是复数的同级敌人时，你可以消耗标准动作并高呼“复肘者，集结！”。所有[复肘者]可以选择立刻插入这个场景，如常投掷先攻并拥有完整的行动轮，这个能力足以跨越非位面级别的空间，但一场影片只能生效1次，这是A级命运来源的传送效果。<br> 在那之后，你与所有复肘者于本次战斗内，将要承受致死伤害时，将那次伤害免疫并将3点生命值恢复为完好。这是A级命运来源的无敌效果，每影片仅会生效一次。</p><p>就算如此也想see you again<br> 价格：B+2500<br> 类型：奇物<br> 描述：一个直升机外形的火焰挂坠，据说史上最强肘术师灌注了他对未来的期望所诞生的饰品。[孩子们，希望这个祝福能让你们走向更光明的未来]<br> 效果：<br> 当你死亡的时候，挂坠会破碎化作一个红色的光球笼罩守护着你。光球会不断治愈着你的伤势，但这个过程中你无法进行任何行动，直到第七天后将你的状态回复至完全。光球拥有等同你生命上限的结构值，若被摧毁则复活失败。这是一个B级祝福来源的复活效果。<br> 当你能够重新行动后，光球会破碎重新化作挂坠。只不过上面的火焰已然黯淡无光，只有回到主神空间重新充能后才能继续守护着你。<br> 握着黯淡的挂坠，这令你充满决心，觉得不会再重蹈覆辙，接下来的一影片时间，你获得快速治疗2（医疗池24）。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
